    std::uint64_t aOrbiterI = 0; std::uint64_t aOrbiterJ = 0; std::uint64_t aOrbiterK = 0;

    // [kdf-a arx]
    std::uint64_t aNonceWordA = TwistMix64::DiffuseA(pNonce * 0xEE70FC52808671FFULL + 0xF3428A6290A8EA8CULL);
    std::uint64_t aNonceWordB = TwistMix64::DiffuseB(pNonce * 0xDC4EF105D57343ADULL + 0xE4E6B0469652905EULL);
    std::uint64_t aNonceWordC = TwistMix64::DiffuseB(pNonce * 0xEAFD1DB52A149AB3ULL + 0x957659DCC242F09FULL);
    std::uint64_t aNonceWordD = TwistMix64::DiffuseB(pNonce * 0xCB9D8B70314315B5ULL + 0xF7C9D32909420D86ULL);
    std::uint64_t aNonceWordE = TwistMix64::DiffuseA(pNonce * 0xC012CC84880FD6C5ULL + 0x9C1E25C18A83CEE5ULL);
    std::uint64_t aNonceWordF = TwistMix64::DiffuseC(pNonce * 0xD70C3AF5312E324DULL + 0x98D458C1498C93FCULL);
    std::uint64_t aNonceWordG = TwistMix64::DiffuseB(pNonce * 0xF22CBD8BE874E2ADULL + 0xBA63B1A75FEE43BDULL);
    std::uint64_t aNonceWordH = TwistMix64::DiffuseA(pNonce * 0x834BA323314F3441ULL + 0x86553F6388F0EFE7ULL);
    std::uint64_t aNonceWordI = TwistMix64::DiffuseC(pNonce * 0xBB62DA7227AB29EFULL + 0x839B5A08E0E8E0F3ULL);
    std::uint64_t aNonceWordJ = TwistMix64::DiffuseB(pNonce * 0xCBBD33A66333120BULL + 0xB965299E9A95F82DULL);
    std::uint64_t aNonceWordK = TwistMix64::DiffuseB(pNonce * 0x9B09909BD330030DULL + 0xC9036A75BDBC1D2CULL);
    std::uint64_t aNonceWordL = TwistMix64::DiffuseC(pNonce * 0xE4B2417908BE1F2BULL + 0xBA57731B6B05D19DULL);
    std::uint64_t aNonceWordM = TwistMix64::DiffuseA(pNonce * 0xEF3ABA8DABADD69BULL + 0x9337EBE0B18578E1ULL);
    std::uint64_t aNonceWordN = TwistMix64::DiffuseA(pNonce * 0xA30F69F747EED809ULL + 0x9879C55EC1857AABULL);
    std::uint64_t aNonceWordO = TwistMix64::DiffuseC(pNonce * 0xD29D95009D850CA7ULL + 0xCCD1E0FB03769C3CULL);
